const data = ctx.data?.objects || [];
const categories = data.map(d => d.status_name);
const amounts = data.map(d => parseFloat(d.total_amount || 0));
const counts = data.map(d => parseInt(d.order_count || 0));
const colorMap = {'草稿':'#d9d9d9','待审批':'#faad14','已审批':'#1677ff','部分到货':'#13c2c2','已到货':'#52c41a','已关闭':'#999','已取消':'#ff4d4f'};
return {
  title: { text: '采购订单状态分布', left: 'center', textStyle: { fontSize: 14 } },
  tooltip: { trigger: 'axis', formatter: p => p.map(s => `${s.seriesName}: ${s.seriesName === '金额' ? '¥' + (s.value/10000).toFixed(1) + '万' : s.value}`).join('<br/>') },
  legend: { bottom: 0 },
  xAxis: { type: 'category', data: categories, axisLabel: { fontSize: 11 } },
  yAxis: [{ type: 'value', name: '数量' }, { type: 'value', name: '金额(万)', axisLabel: { formatter: v => (v/10000).toFixed(0) } }],
  series: [
    { name: '数量', type: 'bar', data: counts, itemStyle: { color: p => colorMap[categories[p.dataIndex]] || '#1677ff', borderRadius: [4,4,0,0] } },
    { name: '金额', type: 'line', yAxisIndex: 1, data: amounts, smooth: true, lineStyle: { color: '#fa8c16' }, itemStyle: { color: '#fa8c16' } }
  ]
};
